import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter a string:");
        String userInput = scanner.nextLine();

        // Check if userInput length exceeds buffer size
        if(userInput.length() > 10) {
            System.out.println("Input string too long. Please enter a shorter string.");
            return;
        }

        // Copy userInput into buffer safely
        byte[] buffer = new byte[10];
        System.arraycopy(userInput.getBytes(), 0, buffer, 0, Math.min(userInput.length(), buffer.length));

        System.out.println("Buffer overflow fixed!");
    }
}

